from collections import deque

def find_exit(dungeon, start, exit_room):
    if start == exit_room:
        return [start]
    parent = {start: None}
    queue = deque([start])
    while queue:
        room = queue.popleft()
        for neighbour in dungeon.get(room, []):
            if neighbour not in parent:
                parent[neighbour] = room
                if neighbour == exit_room:
                    path, node = [], exit_room
                    while node is not None:
                        path.append(node)
                        node = parent[node]
                    return list(reversed(path))
                queue.append(neighbour)
    return []

dungeon = {
    'Entrance': ['Hall', 'Crypt'],
    'Hall':     ['Entrance', 'Armory', 'Garden'],
    'Crypt':    ['Entrance'],
    'Armory':   ['Hall', 'Treasure'],
    'Garden':   ['Hall', 'Exit'],
    'Treasure': ['Armory'],
    'Exit':     ['Garden']
}

print(find_exit(dungeon, 'Entrance', 'Exit'))      # ['Entrance', 'Hall', 'Garden', 'Exit']
print(find_exit(dungeon, 'Entrance', 'Treasure'))  # ['Entrance', 'Hall', 'Armory', 'Treasure']
print(find_exit(dungeon, 'Crypt', 'Exit'))         # ['Crypt', 'Entrance', 'Hall', 'Garden', 'Exit']
